import{_ as a,o as t,c as s,a0 as r}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Player Cross-Event Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/player-cross-event.md","filePath":"analytics/player-cross-event.md"}'),i={name:"analytics/player-cross-event.md"};function l(o,e,n,c,h,d){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="player-cross-event-analytics" tabindex="-1">Player Cross-Event Analytics <a class="header-anchor" href="#player-cross-event-analytics" aria-label="Permalink to &quot;Player Cross-Event Analytics&quot;">​</a></h1><p>The <strong>Player</strong> tab follows one player across many tracked event instances. It is a premium view aimed at alliance leadership.</p><p>For the general locked/active premium behavior, see <a href="./../subscriptions/premium-features.html">Premium Features</a>. This page shows what that pattern looks like specifically for the Player tab.</p><h2 id="locked-state" tabindex="-1">Locked state <a class="header-anchor" href="#locked-state" aria-label="Permalink to &quot;Locked state&quot;">​</a></h2><p>Without the premium player-across-events feature, the tab still opens but shows a locked card and a subscription request button instead of data.</p><blockquote><p>Screenshot placeholder: <code>premium-player-locked.png</code> (S51)</p></blockquote><p>The locked card explains that this feature unlocks:</p><ul><li>cross-event performance</li><li>attendance consistency</li><li>score progression over time</li></ul><h2 id="active-state" tabindex="-1">Active state <a class="header-anchor" href="#active-state" aria-label="Permalink to &quot;Active state&quot;">​</a></h2><p>When the feature is active, you can search for a player by current name or old nickname, or open a player directly from the Kingdom or Alliance analytics tabs.</p><blockquote><p>Screenshot placeholder: <code>premium-player-active.png</code> (S52)</p></blockquote><p>The active Player tab shows:</p><ul><li>a player header with alliance, kingdom, power, Town Center level, and current status</li><li>rank positions inside the alliance and kingdom</li><li>summary cards for total score, average score, internal points, attendance, tracked events, missed events, and points rank</li><li>charts for score history, event discipline, and attendance streak</li><li>a <strong>Cross-Event Consistency</strong> section with the player&#39;s strongest events and overall consistency</li><li>a <strong>Performance by Event</strong> table with attendance, totals, averages, best score, latest score, and points for each event</li></ul><p>There is also a <strong>Full profile</strong> button to jump to the player&#39;s main profile page.</p><h2 id="what-this-tab-is-best-for" tabindex="-1">What this tab is best for <a class="header-anchor" href="#what-this-tab-is-best-for" aria-label="Permalink to &quot;What this tab is best for&quot;">​</a></h2><p>Use it when you need to answer questions like:</p><ul><li>Is this player consistent across events?</li><li>Are they improving or slipping?</li><li>Which event types suit them best?</li><li>Is their attendance strong enough for <a href="./../getting-started/glossary.html#reward-eligibility">reward eligibility</a>?</li></ul><h2 id="related-guides" tabindex="-1">Related guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related guides&quot;">​</a></h2><ul><li><a href="./alliance.html">Alliance Analytics</a></li><li><a href="./recommendations.html">Smart Recommendations</a></li><li><a href="./../how-to/rewards.html">Review Reward Eligibility</a></li></ul>',19)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
